SELECT rb.id, rb.bill_no, rb.contract_id, rb.house_id, rb.landlord_id, rb.tenant_user_id, rb.bill_type, rb.bill_month, rb.utility_payment_mode, rb.rent_amount, rb.deposit_amount, rb.water_amount, rb.electric_amount, rb.total_amount, rb.due_date, rb.remark, rb.utility_proof_url, rb.utility_proof_status, rb.utility_proof_note, rb.pay_status, rb.paid_time, rb.create_time, rb.update_time, rc.contract_no, rc.title AS contract_title, h.name AS house_name, h.cover AS house_cover, lu.username AS landlord_name, tu.username AS tenant_name FROM rental_bill rb LEFT JOIN rental_contract rc ON rc.id = rb.contract_id LEFT JOIN house h ON h.id = rb.house_id LEFT JOIN landlord l ON l.id = rb.landlord_id LEFT JOIN user lu ON lu.id = l.user_id LEFT JOIN user tu ON tu.id = rb.tenant_user_id
AND ( rb.bill_no LIKE concat('%',#{keyword},'%') OR rc.contract_no LIKE concat('%',#{keyword},'%') OR h.name LIKE concat('%',#{keyword},'%') OR tu.username LIKE concat('%',#{keyword},'%') )
AND rb.contract_id = #{contractId}
AND rb.landlord_id = #{landlordId}
AND rb.tenant_user_id = #{tenantUserId}
AND rb.bill_type = #{billType}
AND rb.pay_status = #{payStatus}
AND rb.utility_payment_mode = #{utilityPaymentMode}
AND rb.utility_proof_status = #{utilityProofStatus}
ORDER BY rb.id DESC
LIMIT #{current},#{size}

SELECT COUNT(*)
FROM rental_bill rb
LEFT JOIN rental_contract rc ON rc.id = rb.contract_id
LEFT JOIN house h ON h.id = rb.house_id
LEFT JOIN user tu ON tu.id = rb.tenant_user_id


        AND (
            rb.bill_no LIKE concat('%',#{keyword},'%')
            OR rc.contract_no LIKE concat('%',#{keyword},'%')
            OR h.name LIKE concat('%',#{keyword},'%')
            OR tu.username LIKE concat('%',#{keyword},'%')
        )


        AND rb.contract_id = #{contractId}


        AND rb.landlord_id = #{landlordId}


        AND rb.tenant_user_id = #{tenantUserId}


        AND rb.bill_type = #{billType}


        AND rb.pay_status = #{payStatus}


        AND rb.utility_payment_mode = #{utilityPaymentMode}


        AND rb.utility_proof_status = #{utilityProofStatus}

SELECT COUNT(*)
FROM rental_bill
WHERE contract_id = #{contractId}
  AND bill_type = #{billType}

    AND bill_month = #{billMonth}


    AND (bill_month IS NULL OR bill_month = '')
